// Regenerates registry/js/all.js — the behavior-layer bundle. Concatenates
// core.js first, then every component behavior, so an HTML user can drop in a
// single <script> and get interactivity for all .jl-* components.
//
// Run after adding or removing a behavior file:
//   node registry/scripts/build-js-bundle.mjs
import { readdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const jsDir = join(__dirname, "..", "js");

const CORE = "core.js";
const UTIL = "util.js"; // shared helpers — load right after core, not a behavior
const EXCLUDE = new Set(["all.js"]);

const all = readdirSync(jsDir).filter((f) => f.endsWith(".js") && !EXCLUDE.has(f));
const behaviors = all.filter((f) => f !== CORE && f !== UTIL).sort();
const order = [CORE, ...(all.includes(UTIL) ? [UTIL] : []), ...behaviors];

const header =
  "/* JLDS — behavior layer bundle. Auto-generated by scripts/build-js-bundle.mjs — do not edit by hand. */\n" +
  "/* Core + every component behavior. Progressive enhancement: load after your markup (defer is fine). */\n\n";

const body = order
  .map((f) => `/* ---- ${f} ---- */\n${readFileSync(join(jsDir, f), "utf8").trim()}\n`)
  .join("\n");

writeFileSync(join(jsDir, "all.js"), header + body);
console.log(`Wrote registry/js/all.js (${behaviors.length} behaviors)`);
